{"query":"with ranges as (
  select min(digitalbankinglogintransaction_timestamp) as min_ts,
         max(digitalbankinglogintransaction_timestamp) as max_ts,
         count(*) as login_rows
  from fact.digitalbankinglogintransaction
),
statuses as (
  select json_agg(json_build_object('status', digitalbankinguser_current_status, 'count', cnt) order by cnt desc) as status_counts
  from (
    select coalesce(digitalbankinguser_current_status,'<null>') as digitalbankinguser_current_status, count(*) as cnt
    from dim.digitalbankinguser
    group by 1
  ) s
),
flags as (
  select json_agg(json_build_object('dss_current_flag', dss_current_flag, 'count', cnt) order by cnt desc) as flag_counts
  from (
    select coalesce(dss_current_flag,'<null>') as dss_current_flag, count(*) as cnt
    from dim.digitalbankinguser
    group by 1
  ) f
),
purged as (
  select json_agg(json_build_object('purged', digitalbankinguser_purged_from_source_system, 'count', cnt) order by cnt desc) as purged_counts
  from (
    select coalesce(digitalbankinguser_purged_from_source_system,'<null>') as digitalbankinguser_purged_from_source_system, count(*) as cnt
    from dim.digitalbankinguser
    group by 1
  ) p
)
select * from ranges cross join statuses cross join flags cross join purged;"}

