{"query":"with stats as (
  select json_agg(x order by src) as key_stats
  from (
    select 'dim' as src, min(dim_digitalbankinguser_key) as min_key, max(dim_digitalbankinguser_key) as max_key, count(*) as rows from dim.digitalbankinguser
    union all
    select 'fact' as src, min(dim_digitalbankinguser_key), max(dim_digitalbankinguser_key), count(*) from fact.digitalbankinglogintransaction
  ) x
),
dim_sample as (
  select json_agg(dim_digitalbankinguser_key order by dim_digitalbankinguser_key) as dim_keys
  from (select dim_digitalbankinguser_key from dim.digitalbankinguser order by 1 limit 5) d
),
fact_sample as (
  select json_agg(dim_digitalbankinguser_key order by dim_digitalbankinguser_key) as fact_keys
  from (select dim_digitalbankinguser_key from fact.digitalbankinglogintransaction order by 1 limit 5) f
)
select * from stats cross join dim_sample cross join fact_sample;"}
